            i.putExtras(bundle);
            startActivity(i);
        });

        ibSettings = findViewById(R.id.ib_settings);
        ibSettings.setOnClickListener(v -> {
            Intent i = new Intent(ProgressActivity.this, Setting.class);
            Bundle bundle = new Bundle();
