    public void getDetailHabit(String idHabit, String idTaiKhoan) {
        TextView tvDetail = (TextView) findViewById(R.id.tvDetail);
        txtDIM = (TextView) findViewById(R.id.tvDoneinMonth);
        txtTTD = (TextView) findViewById(R.id.tvTotalDone);
        txtVTT = (TextView) findViewById(R.id.tvVolTotal);
        txtCS = (TextView) findViewById(R.id.tvCurrentStreak);

        databaseHelper = HabitDatabaseHelper.getInstance(this);
        try {
            Habit currentHabit = databaseHelper.getHabit(idTaiKhoan, idHabit);
            if (currentHabit == null) {
                Toast.makeText(ProgressActivity.this, "Không tìm thấy dữ liệu", Toast.LENGTH_SHORT).show();
                return;
            }

            Arrays.fill(perfectArr, 0);
            List<HabitAction> actions = databaseHelper.getHabitActions(idTaiKhoan, idHabit);
            for (HabitAction action : actions) {
                if (databaseHelper.isInCurrentMonth(action.getActionTime())) {
                    Calendar calendar = databaseHelper.parseActionTime(action.getActionTime());
                    if (calendar != null) {
                        perfectArr[calendar.get(Calendar.DAY_OF_MONTH)] = 1;
                    }
                }
            }

            tvDetail.setText(currentHabit.getTen());
            txtTTD.setText(databaseHelper.getTotalDaysWithProgress(idTaiKhoan, idHabit) + " Days");
            txtVTT.setText(String.format("%.1f", databaseHelper.getTotalProgress(idTaiKhoan, idHabit)) + " " + currentHabit.getDonVi());
            txtDIM.setText(databaseHelper.getDoneInCurrentMonth(idTaiKhoan, idHabit) + " Days");
            txtCS.setText(getCurrentSteak() + " Days");
        } catch (Exception e) {
            Toast.makeText(ProgressActivity.this, e.toString() + "\n", Toast.LENGTH_LONG).show();
            Log.d("Error", e.toString());
        }
    }

    public void inforHabit(String idHabit, String idTaiKhoan) {
        Dialog dialog = new Dialog(this);
        dialog.setContentView(R.layout.dialog_infor);

        Log.d("idHabit", idHabit);
        Log.d("idUser", acc.getUsername());
        databaseHelper = HabitDatabaseHelper.getInstance(this);


        EditText edt_name = (EditText) dialog.findViewById(R.id.edt_name);
        TextInputEditText edt_decription = (TextInputEditText) dialog.findViewById(R.id.edt_decription);
        EditText edt_unit_increase = (EditText) dialog.findViewById(R.id.edt_unit_increase);
        EditText edt_time_range = (EditText) dialog.findViewById(R.id.edt_time_range);
        EditText edt_reminder = (EditText) dialog.findViewById(R.id.edt_reminder);
        TextInputEditText edt_reminder_message = (TextInputEditText) dialog.findViewById(R.id.edt_reminder_message);
        EditText edt_start_term = (EditText) dialog.findViewById(R.id.edt_start_term);
        EditText edt_end_term = (EditText) dialog.findViewById(R.id.edt_end_term);
        EditText edt_goal = (EditText) dialog.findViewById(R.id.edt_goal);
        EditText edt_unit = (EditText) dialog.findViewById(R.id.edt_unit);
        EditText edt_period = (EditText) dialog.findViewById(R.id.edt_period);
        ImageView img_close = (ImageView) dialog.findViewById(R.id.img_close);

        Habit currentHabit = databaseHelper.getHabit(idTaiKhoan, idHabit);
        if (currentHabit != null) {
            edt_name.setText(currentHabit.getTen());
            edt_decription.setText(currentHabit.getMoTa());
            edt_unit_increase.setText(String.valueOf(currentHabit.getDonViTang()));
            edt_time_range.setText(currentHabit.getThoiDiem());
            edt_reminder.setText(currentHabit.getThoiGianNhacNho());
            edt_reminder_message.setText(currentHabit.getLoiNhacNho());
            edt_start_term.setText(currentHabit.getThoiGianBatDau());
            edt_end_term.setText(currentHabit.getThoiGianKetThuc());
            edt_goal.setText(String.valueOf((long) currentHabit.getMucTieu()));
            edt_unit.setText(currentHabit.getDonVi());
            edt_period.setText(currentHabit.getKhoangThoiGian());
        }


        dialog.show();

        Window window = dialog.getWindow();
        if (window != null) {
            WindowManager.LayoutParams layoutParams = new WindowManager.LayoutParams();
            layoutParams.copyFrom(window.getAttributes());
            layoutParams.width = WindowManager.LayoutParams.MATCH_PARENT;
            layoutParams.height = WindowManager.LayoutParams.WRAP_CONTENT;
            window.setAttributes(layoutParams);
        }

        img_close.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                dialog.cancel();
            }
        });
    }


    public void deleteHabit(String userId,String habbitId){
        String idHabit = getIntent().getStringExtra("idThoiQuen");
        String idTaiKhoan = getIntent().getStringExtra("idTaiKhoan");
        AlertDialog.Builder builder = new AlertDialog.Builder(ProgressActivity.this);
        LayoutInflater inflater = getLayoutInflater();

        @SuppressLint("ResourceType")
        View dialogView = inflater.inflate(R.drawable.dialog_delete, null);
        builder.setView(dialogView);

        TextView title = dialogView.findViewById(R.id.dialogTitle);
        title.setText("Delete Habit?");

        TextView message = dialogView.findViewById(R.id.dialogMessage);
        message.setText("Do you want to remove this habit?" +
                "\nThis action cannot be undone");
        message.setGravity(Gravity.CENTER);
        builder.setPositiveButton("Delete", new DialogInterface.OnClickListener() {
                    @Override
                    public void onClick(DialogInterface dialog, int which) {
                        chageTrangThai(idTaiKhoan,idHabit);
                        Toast.makeText(getApplicationContext(), "Deleted successfully", Toast.LENGTH_SHORT).show();
                        Intent intent = new Intent(ProgressActivity.this, Home_Activity.class);
                        Bundle bundle = new Bundle();
                        bundle.putSerializable("user_account", acc);
                        intent.putExtra("idTaiKhoan", idTaiKhoan);
                        intent.putExtras(bundle);
                        startActivity(intent);
                    }
                })
                .setNegativeButton("Cancel", new DialogInterface.OnClickListener() {
                    @Override
                    public void onClick(DialogInterface dialog, int which) {
                        dialog.cancel();
                    }
                })
                .show();
    }

    public void getConnection(String idUser, String idHabit) {
        databaseHelper = HabitDatabaseHelper.getInstance(this);
    }
    public int countDay()
    {
        int day = 0;
        for (int i = 0; i < perfectArr.length; i++)
        {
            if(perfectArr[i] == 1)
                day++;
        }
        return day;
    }
    public int getCurrentSteak()
    {
        int maxStreak = 0;
        int streak = 1;
        for(int i = 0; i < perfectArr.length - 1; i++)
        {
            if(perfectArr[i] == 1 && perfectArr[i+1] == 1)
                streak++;
            else if (perfectArr[i] == 0)
            {
                if(maxStreak <= streak)
                {
                    maxStreak = streak;
                    streak = 1;
                }
            }
        }
        return (maxStreak == 1) ? 0 : maxStreak;
    }
    public void chageTrangThai(String userId,String habbitId){
        databaseHelper = HabitDatabaseHelper.getInstance(this);
        databaseHelper.deleteHabit(userId, habbitId);
    }
    public void editHabit(String idhabit, String idTaiKhoan){
                Intent i = new Intent(ProgressActivity.this, Edit_habit.class );
                // Tạo Bundle và đặt đối tượng habit vào Bundle
                Bundle bundlehabit = new Bundle();
                i.putExtra("idTaiKhoan",idTaiKhoan);
                i.putExtra("idThoiQuen",idhabit);
                i.putExtras(bundlehabit);
                startActivity(i);
    }
}

package com.example.finalproject.activities;

import android.os.Bundle;

import androidx.annotation.NonNull;
import androidx.fragment.app.Fragment;

import android.util.Log;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;

import com.example.finalproject.R;
import com.github.mikephil.charting.charts.PieChart;
import com.github.mikephil.charting.components.Legend;
import com.github.mikephil.charting.data.PieData;
import com.github.mikephil.charting.data.PieDataSet;
import com.github.mikephil.charting.data.PieEntry;
import com.google.firebase.database.DataSnapshot;
import com.google.firebase.database.DatabaseError;
import com.google.firebase.database.DatabaseReference;
import com.google.firebase.database.FirebaseDatabase;
import com.google.firebase.database.ValueEventListener;

import android.graphics.Color;
import android.widget.TextView;
import android.widget.Toast;

import org.w3c.dom.Text;

import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Calendar;
import java.util.Date;

/**
 * A simple {@link Fragment} subclass.
 * Use the {@link ProgressDayFragment#newInstance} factory method to
 * create an instance of this fragment.
 */
public class ProgressDayFragment extends Fragment {
    private PieChart pieChart;

    // TODO: Rename parameter arguments, choose names that match
    // the fragment initialization parameters, e.g. ARG_ITEM_NUMBER
    private static final String ARG_PARAM1 = "param1";
    private static final String ARG_PARAM2 = "param2";

    // TODO: Rename and change types of parameters
    private String mParam1;
    private String mParam2;
    private FirebaseDatabase dataBase;
    private DatabaseReference ref;
    private TextView tvTodayProgress;
    private TextView tvCurrentProgress;

    public ProgressDayFragment() {
        // Required empty public constructor
    }

    /**
     * Use this factory method to create a new instance of
     * this fragment using the provided parameters.
     *
     * @param param1 Parameter 1.
     * @param param2 Parameter 2.
     * @return A new instance of fragment ProgressDayFragment.
     */
    // TODO: Rename and change types and number of parameters
    public static ProgressDayFragment newInstance(String param1, String param2) {
        ProgressDayFragment fragment = new ProgressDayFragment();
        Bundle args = new Bundle();
        args.putString(ARG_PARAM1, param1);
        args.putString(ARG_PARAM2, param2);
        fragment.setArguments(args);
        return fragment;
    }

    public static ProgressDayFragment newInstance(String idHabit, String idTaiKhoan, String test) {
        ProgressDayFragment fragment = new ProgressDayFragment();
        Bundle args = new Bundle();
        args.putString("idHabit", idHabit);
        args.putString("idTaiKhoan", idTaiKhoan);
        args.putString("test", test);
        fragment.setArguments(args);
        return fragment;
    }

    @Override
    public void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        if (getArguments() != null) {
            mParam1 = getArguments().getString(ARG_PARAM1);
            mParam2 = getArguments().getString(ARG_PARAM2);
        }
    }

    @Override
    public View onCreateView(LayoutInflater inflater, ViewGroup container,
                             Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_progress_day, container, false);
        // Lấy dữ liệu
        String idHabit = getArguments().getString("idHabit");
        String idTaiKhoan = getArguments().getString("idTaiKhoan");

        pieChart = view.findViewById(R.id.pieChart);
        tvTodayProgress = view.findViewById(R.id.tvTodayProgress);
        tvCurrentProgress = view.findViewById(R.id.tvCurrentProgress);

        setUpPieChart();
        getProgressDay(idTaiKhoan,idHabit);

        // Inflate the layout for this fragment
        return view;
    }
    private void getConnection(String idTaiKhoan, String idHabit){
        dataBase = FirebaseDatabase.getInstance();
        ref = dataBase.getReference("Habit_Tracker").child("Du_Lieu").child(idTaiKhoan).child(idHabit);
    }
    private void getProgressDay(String idTaiKhoan, String idHabit){
        getConnection(idTaiKhoan,idHabit);
        ref.addListenerForSingleValueEvent(new ValueEventListener() {
            @Override
            public void onDataChange(@NonNull DataSnapshot dataSnapshot) {
                if(dataSnapshot.exists()){
                    try {
                        double target = dataSnapshot.child("MucTieu").getValue(Double.class);
                        String period = dataSnapshot.child("KhoangThoiGian").getValue(String.class);
                        target = calculateTarget(target, period);
                        String donvi = dataSnapshot.child("DonVi").getValue(String.class);
                        tvTodayProgress.setText("Target "+String.format("%.1f", target)+" "+donvi);

                        // Tính tổng khối lượng công việc đã thực hiện trong ngày
                        double tongKhoiLuong = 0;
                        for (DataSnapshot snapshot : dataSnapshot.child("ThoiGianThucHien").getChildren()) {
                            String thoiGian = snapshot.getKey();
                            SimpleDateFormat sdf = new SimpleDateFormat("dd-MM-yyyy hh:mm:ssa");
                            Date date = sdf.parse(thoiGian);
                            Calendar cal = Calendar.getInstance();
                            cal.setTime(date);
                            Calendar today = Calendar.getInstance();
                            if (cal.get(Calendar.YEAR) == today.get(Calendar.YEAR) &&
                                    cal.get(Calendar.DAY_OF_YEAR) == today.get(Calendar.DAY_OF_YEAR)) {
                                tongKhoiLuong += snapshot.getValue(Double.class);
                            }
                        }

                        tvCurrentProgress.setText(String.format("%.1f", tongKhoiLuong)+" "+donvi);
                        loadPieChartData(tongKhoiLuong,target);
                        pieChart.invalidate();
                    }catch (Exception e){
                        Log.d("Error", e.getMessage());
                    }
                }
                else
                    Toast.makeText(getContext(), "Không tìm thấy dữ liệu", Toast.LENGTH_SHORT).show();
            }

            @Override
            public void onCancelled(@NonNull DatabaseError error) {
                Toast.makeText(getContext(), "Lỗi khi đọc dữ liệu từ Firebase", Toast.LENGTH_SHORT).show();
            }
        });
    }
    public double calculateTarget(double target, String period)
    {
        double result = 0;
        if(period.equals("Day"))
            return target;
        else if(period.equals("Week"))
            return (target/ 7);
        else if (period.equals("Month"))
            return (target/ 30);
        return result;
    }
    private void setUpPieChart() {
        pieChart.setUsePercentValues(false);
        pieChart.getDescription().setEnabled(false);
        pieChart.setExtraOffsets(5, 10, 5, 5);
        pieChart.setDragDecelerationFrictionCoef(0.95f);
        pieChart.setDrawHoleEnabled(true);
        pieChart.setHoleColor(0);
        pieChart.setTransparentCircleRadius(61f);


        Legend l = pieChart.getLegend();
        l.setVerticalAlignment(Legend.LegendVerticalAlignment.TOP);
        l.setHorizontalAlignment(Legend.LegendHorizontalAlignment.RIGHT);
        l.setOrientation(Legend.LegendOrientation.VERTICAL);
        l.setDrawInside(false);
        l.setEnabled(false);
    }
    private void loadPieChartData(double tongKhoiLuong, double muctieu) {
        // creating data values
        ArrayList<PieEntry> entries = new ArrayList<>();

        if (tongKhoiLuong >= muctieu) {
            // Nếu tổng khối lượng lớn hơn hoặc bằng mục tiêu, thêm một phần tử với giá trị là 100%
            entries.add(new PieEntry(100f, ""));
        } else {
            // Nếu tổng khối lượng nhỏ hơn mục tiêu, tính phần trăm và thêm vào danh sách
            float percentageCompleted = (float) (tongKhoiLuong / muctieu * 100);
            entries.add(new PieEntry(percentageCompleted, ""));
            entries.add(new PieEntry(100 - percentageCompleted, ""));
        }

        // creating dataset
        PieDataSet dataset = new PieDataSet(entries, "");
        dataset.setSliceSpace(3f);
        dataset.setSelectionShift(5f);
        dataset.setDrawValues(false);
        int[] colors = {R.color.Blue, R.color.white};
        dataset.setColors(colors, getContext());

        // creating data
        PieData data = new PieData(dataset);
        data.setValueTextSize(10f);
        data.setValueTextColor(Color.BLACK);

        // setting data
        pieChart.setData(data);
    }

}

